void print_error_info(const featherdoc::document_error_info &error_info) {
    const auto &error = error_info.code;
    std::cerr << (error ? error.message() : std::string{"operation failed"});
    if (!error_info.detail.empty()) {
        std::cerr << ": " << error_info.detail;
    }
    if (!error_info.entry_name.empty()) {
        std::cerr << " [entry=" << error_info.entry_name << ']';
    }
    if (error_info.xml_offset.has_value()) {
        std::cerr << " [xml_offset=" << *error_info.xml_offset << ']';
    }
    std::cerr << '\n';
}

void print_parse_error(const std::string &message) {
    std::cerr << message << '\n';
    print_usage(std::cerr);
}

auto has_json_flag(const std::vector<std::string_view> &arguments) -> bool {
    for (const auto argument : arguments) {
        if (argument == "--json") {
            return true;
        }
    }

    return false;
}

template <typename UInt>
auto parse_unsigned_integer(std::string_view text, UInt &value) -> bool {
    if (text.empty()) {
        return false;
    }

    UInt result = 0;
    for (const auto ch : text) {
        if (ch < '0' || ch > '9') {
            return false;
        }

        const auto digit = static_cast<UInt>(ch - '0');
        if (result > (std::numeric_limits<UInt>::max() - digit) / 10) {
            return false;
        }
        result = static_cast<UInt>(result * 10 + digit);
    }

    value = result;
    return true;
}

auto parse_index(std::string_view text, std::size_t &value) -> bool {
    return parse_unsigned_integer(text, value);
}

auto parse_uint32(std::string_view text, std::uint32_t &value) -> bool {
    return parse_unsigned_integer(text, value);
}

auto parse_int32(std::string_view text, std::int32_t &value) -> bool {
    if (text.empty()) {
        return false;
    }

    auto digits = text;
    bool negative = false;
    if (digits.front() == '+' || digits.front() == '-') {
        negative = digits.front() == '-';
        digits.remove_prefix(1);
    }
    if (digits.empty()) {
        return false;
    }

    std::uint64_t magnitude = 0;
    for (const auto ch : digits) {
        if (ch < '0' || ch > '9') {
            return false;
        }

        const auto digit = static_cast<std::uint64_t>(ch - '0');
        constexpr auto positive_limit =
            static_cast<std::uint64_t>(std::numeric_limits<std::int32_t>::max());
        constexpr auto negative_limit = positive_limit + 1;
        const auto limit = negative ? negative_limit : positive_limit;
        if (magnitude > (limit - digit) / 10) {
            return false;
        }
        magnitude = magnitude * 10 + digit;
    }

    if (negative) {
        if (magnitude == static_cast<std::uint64_t>(std::numeric_limits<std::int32_t>::max()) +
                             1ULL) {
            value = std::numeric_limits<std::int32_t>::min();
            return true;
        }

        value = -static_cast<std::int32_t>(magnitude);
        return true;
    }

    value = static_cast<std::int32_t>(magnitude);
    return true;
}

auto parse_bool(std::string_view text, bool &value) -> bool {
    if (text == "true" || text == "yes" || text == "1") {
        value = true;
        return true;
    }
    if (text == "false" || text == "no" || text == "0") {
        value = false;
        return true;
    }

    return false;
}

auto parse_page_orientation(std::string_view text,
                            featherdoc::page_orientation &orientation) -> bool {
    if (text == "portrait") {
        orientation = featherdoc::page_orientation::portrait;
        return true;
    }
    if (text == "landscape") {
        orientation = featherdoc::page_orientation::landscape;
        return true;
    }

    return false;
}

auto parse_list_kind(std::string_view text, featherdoc::list_kind &kind) -> bool {
    if (text == "bullet") {
        kind = featherdoc::list_kind::bullet;
        return true;
    }
    if (text == "decimal") {
        kind = featherdoc::list_kind::decimal;
        return true;
    }

    return false;
}

auto parse_reference_kind(std::string_view text,
                          featherdoc::section_reference_kind &reference_kind) -> bool {
    if (text == "default") {
        reference_kind = featherdoc::section_reference_kind::default_reference;
        return true;
    }
    if (text == "first") {
        reference_kind = featherdoc::section_reference_kind::first_page;
        return true;
    }
    if (text == "even") {
        reference_kind = featherdoc::section_reference_kind::even_page;
        return true;
    }

    return false;
}

auto parse_floating_image_horizontal_reference(
    std::string_view text,
    featherdoc::floating_image_horizontal_reference &reference) -> bool {
    if (text == "page") {
        reference = featherdoc::floating_image_horizontal_reference::page;
        return true;
    }
    if (text == "margin") {
        reference = featherdoc::floating_image_horizontal_reference::margin;
        return true;
    }
    if (text == "column") {
        reference = featherdoc::floating_image_horizontal_reference::column;
        return true;
    }
    if (text == "character") {
        reference = featherdoc::floating_image_horizontal_reference::character;
        return true;
    }

    return false;
}

auto parse_floating_image_vertical_reference(
    std::string_view text,
    featherdoc::floating_image_vertical_reference &reference) -> bool {
    if (text == "page") {
        reference = featherdoc::floating_image_vertical_reference::page;
        return true;
    }
    if (text == "margin") {
        reference = featherdoc::floating_image_vertical_reference::margin;
        return true;
    }
    if (text == "paragraph") {
        reference = featherdoc::floating_image_vertical_reference::paragraph;
        return true;
    }
    if (text == "line") {
        reference = featherdoc::floating_image_vertical_reference::line;
        return true;
    }

    return false;
}

auto parse_floating_image_wrap_mode(std::string_view text,
                                    featherdoc::floating_image_wrap_mode &mode)
    -> bool {
    if (text == "none") {
        mode = featherdoc::floating_image_wrap_mode::none;
        return true;
    }
    if (text == "square") {
        mode = featherdoc::floating_image_wrap_mode::square;
        return true;
    }
    if (text == "top_bottom" || text == "top-bottom") {
        mode = featherdoc::floating_image_wrap_mode::top_bottom;
        return true;
    }

    return false;
}

auto read_zip_entry_text(zip_t *archive, std::string_view entry_name,
                         std::string &content) -> zip_entry_read_status {
    if (zip_entry_open(archive, std::string(entry_name).c_str()) < 0) {
        return zip_entry_read_status::missing;
    }

    void *buffer = nullptr;
    std::size_t size = 0;
    if (zip_entry_read(archive, &buffer, &size) < 0) {
        zip_entry_close(archive);
        return zip_entry_read_status::read_failed;
    }

    if (buffer != nullptr && size != 0U) {
        content.assign(static_cast<const char *>(buffer), size);
    } else {
        content.clear();
    }

    std::free(buffer);
    zip_entry_close(archive);
    return zip_entry_read_status::ok;
}

auto normalize_word_part_entry(std::string_view target) -> std::string {
    std::string normalized(target);
    for (auto &character : normalized) {
        if (character == '\\') {
            character = '/';
        }
    }

    if (!normalized.empty() && normalized.front() == '/') {
        normalized.erase(normalized.begin());
    }

    if (normalized.rfind("word/", 0U) == 0U) {
        return normalized;
    }

    return "word/" + normalized;
}

auto parse_options(const std::vector<std::string_view> &arguments,
                   std::size_t start_index, bool allow_no_inherit,
                   command_options &options, std::string &error_message)
    -> bool {
    for (std::size_t index = start_index; index < arguments.size(); ++index) {
        const auto argument = arguments[index];
        if (allow_no_inherit && argument == "--no-inherit") {
            options.inherit_header_footer = false;
            continue;
        }

        if (argument == "--output") {
            if (options.output_path.has_value()) {
                error_message = "duplicate --output option";
                return false;
            }
            if (index + 1 >= arguments.size()) {
                error_message = "missing path after --output";
                return false;
            }

            options.output_path = path_type(std::string(arguments[index + 1]));
            ++index;
            continue;
        }

        if (argument == "--json") {
            options.json_output = true;
            continue;
        }

        error_message = "unknown option: " + std::string(argument);
        return false;
    }

    return true;
}

auto parse_export_template_schema_options(
    const std::vector<std::string_view> &arguments, std::size_t start_index,
    export_template_schema_options &options, std::string &error_message) -> bool {
    for (std::size_t index = start_index; index < arguments.size(); ++index) {
        const auto argument = arguments[index];
        if (argument == "--section-targets") {
            if (options.resolved_section_targets) {
                error_message =
                    "--section-targets conflicts with --resolved-section-targets";
                return false;
            }
            options.section_targets = true;
            continue;
        }

        if (argument == "--resolved-section-targets") {
            if (options.section_targets) {
                error_message =
                    "--resolved-section-targets conflicts with --section-targets";
                return false;
            }
            options.resolved_section_targets = true;
            continue;
        }

        if (argument == "--output") {
            if (options.output_path.has_value()) {
                error_message = "duplicate --output option";
                return false;
            }
            if (index + 1U >= arguments.size()) {
                error_message = "missing path after --output";
                return false;
            }

            options.output_path = path_type(std::string(arguments[index + 1U]));
            ++index;
            continue;
        }

        if (argument == "--json") {
            options.json_output = true;
            continue;
        }

        error_message = "unknown option: " + std::string(argument);
        return false;
    }

    return true;
}

